import { Etcd3 } from 'etcd3';
import os from 'os';
import path from 'path';
import fs from 'fs';
import { isNodeSealed, encrypt, decrypt } from './secrets.js';

let etcdHosts = process.env.ETCD_HOSTS ? process.env.ETCD_HOSTS.split(',') : ['core-docker-etcd:2379'];
const etcdUsername = process.env.ETCD_USERNAME || undefined;
const etcdPassword = process.env.ETCD_PASSWORD || undefined;

function buildEtcdOptions(hosts) {
  const opts = { hosts: hosts || etcdHosts };

  // 1. Try auth file (generated by bootstrapEtcd)
  const authFile = path.join('/mnt/backup', '__system__', 'etcd', 'auth.json');
  if (authFile && fs.existsSync(authFile)) {
    try {
      const auth = JSON.parse(fs.readFileSync(authFile, 'utf8'));
      if (auth.username && auth.password) {
        opts.auth = { username: auth.username, password: auth.password };
        return opts;
      }
    } catch (e) {
      console.warn('[DB] Failed to read etcd auth file:', e.message);
    }
  }

  // 2. Fall back to env vars (for external etcd)
  if (etcdUsername && etcdPassword) {
    opts.auth = { username: etcdUsername, password: etcdPassword };
  }

  return opts;
}

let etcd = new Etcd3(buildEtcdOptions());

export const reconnectEtcd = async (hosts) => {
  if (hosts) etcdHosts = hosts;
  try { await etcd.close(); } catch {}
  etcd = new Etcd3(buildEtcdOptions());
  // Verify the new connection is ready
  try {
    await etcd.get('__etcd_health_check').string();
  } catch {}
  console.log('[DB] Reconnected to ETCD with updated credentials.');
};

export const closeEtcd = () => {
  console.log('[DB] Closing ETCD connection...');
  etcd.close();
};

/**
 * CoreDB Wrapper to handle encryption for secrets only
 */
class CoreDB {
  _shouldEncrypt(key) {
    return key.startsWith('secrets/') || key.startsWith('core/containers/') || key.startsWith('core/groups/');
  }

  _processValue(key, value, decrypting = false) {
    if (!value) return null;
    let processed = value;

    if (this._shouldEncrypt(key)) {
      if (!decrypting) {
        processed = typeof processed === 'string' ? processed : JSON.stringify(processed);
      }
      processed = decrypting ? decrypt(value) : encrypt(processed);
    }

    if (decrypting) {
      try { return JSON.parse(processed); } catch (e) { return processed; }
    }
    return typeof processed === 'string' ? processed : JSON.stringify(processed);
  }

  async put(key, value) {
    const finalValue = this._processValue(key, value);
    return await etcd.put(key).value(finalValue);
  }

  async get(key) {
    const rawValue = await etcd.get(key).string();
    return this._processValue(key, rawValue, true);
  }

  async getAll(prefix) {
    const all = await etcd.getAll().prefix(prefix).strings();
    const results = {};
    for (const [key, value] of Object.entries(all)) {
      results[key] = this._processValue(key, value, true);
    }
    return results;
  }

  async delete(key) {
    return await etcd.delete().key(key);
  }
}

const db = new CoreDB();

export const updateEtcdHosts = (newHosts) => {
  if (!newHosts || newHosts.length === 0) return;
  const hostStr = Array.isArray(newHosts) ? newHosts.join(',') : newHosts;
  process.env.ETCD_HOSTS = hostStr;
  etcdHosts = hostStr.split(',');
  console.log(`[DB] Switching ETCD hosts to: ${hostStr}`);
  reconnectEtcd(etcdHosts);
};

export const waitForEtcd = async (retries = 60, delay = 2000) => {
  const host = etcdHosts[0];
  console.log(`Connecting to ETCD at ${host}...`);
  for (let i = 0; i < retries; i++) {
    try {
      await etcd.put('connection-test').value(Date.now().toString());
      console.log('Successfully connected to ETCD.');
      return true;
    } catch (e) {
      console.error(`ETCD connection attempt ${i + 1} failed: ${e.message}`);

      if (i === retries - 1) throw new Error(`Could not connect to ETCD after ${retries} attempts: ${e.message}`);

      reconnectEtcd();

      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }
};

const PREFIX = 'core/containers/';
const NODE_PREFIX = 'nodes/';
const GROUPS_PREFIX = 'core/groups/';

let nodeLease = null;
let _leaseReconnectTimer = null;

export const registerLocalNode = async (nodeId, name, ip, clientIp) => {
  if (nodeLease) {
    try {
      await nodeLease.revoke();
    } catch (e) {
      console.warn(`[DB] Failed to revoke previous lease for Node ${nodeId}: ${e.message}`);
    }
  }

  nodeLease = etcd.lease(30); // 30 second TTL
  nodeLease.on('lost', () => {
    if (_leaseReconnectTimer) return; // debounce — already scheduling a reconnect
    console.error('Node lease lost, re-registering in 5s...');
    _leaseReconnectTimer = setTimeout(() => {
      _leaseReconnectTimer = null;
      registerLocalNode(nodeId, name, ip, clientIp);
    }, 5000);
  });

  const node = {
    id: nodeId,
    name,
    ip,
    clientIp: clientIp || ip,
    status: 'online',
    sealed: isNodeSealed(),
    lastSeen: Date.now(),
    system: {
      totalMem: os.totalmem(),
      cpus: os.cpus().length
    }
  };
  // Nodes are NOT encrypted, they use NODE_PREFIX which does not start with core/
  await nodeLease.put(`${NODE_PREFIX}${nodeId}`).value(JSON.stringify(node));

  // Write DNS entries to SkyDNS so CoreDNS picks them up immediately
  // (no need to wait for the 120s reconciler cycle)
  try {
    const dnsIp = clientIp || ip;
    const domains = [`skydns/local/core-docker/${name}`];

    // If clusterDomain is configured, add per-node subdomain
    const settingsStr = await etcd.get('cluster/settings').string().catch(() => null);
    if (settingsStr) {
      const settings = JSON.parse(settingsStr);
      if (settings.clusterDomain) {
        const parts = settings.clusterDomain.split('.').reverse();
        domains.push(`skydns/${parts.join('/')}/${name}`);
      }
    }

    for (const dnsKey of domains) {
      await etcd.put(dnsKey).value(JSON.stringify({ host: dnsIp }));
    }
  } catch (e) {
    console.warn(`[DB] Failed to write SkyDNS entries for node ${name}: ${e.message}`);
  }

  console.log(`Node ${nodeId} registered with lease (Sealed: ${node.sealed}).`);
};

export const getNodes = async () => {
  try {
    const allNodes = await db.getAll(NODE_PREFIX);
    return Object.values(allNodes);
  } catch (e) {
    console.error(`Failed to get nodes from ETCD: ${e.message}`);
    throw e;
  }
};

export const saveNode = async (id, name, ip, status = 'offline', clientIp) => {
  const node = {
    id,
    name,
    ip,
    clientIp: clientIp || ip,
    status,
    backupPath: process.env.HOST_BACKUP_PATH || '/data/backup',
    nonBackupPath: process.env.HOST_NONBACKUP_PATH || '/data/non-backup'
  };
  await db.put(`${NODE_PREFIX}${id}`, node);
};

export const deleteNode = async (id) => {
  // Clean up SkyDNS entries
  try {
    const nodeData = await db.get(`${NODE_PREFIX}${id}`);
    if (nodeData) {
      const node = JSON.parse(nodeData);
      await etcd.delete().key(`skydns/local/core-docker/${node.name}`);
      const settingsStr = await etcd.get('cluster/settings').string().catch(() => null);
      if (settingsStr) {
        const settings = JSON.parse(settingsStr);
        if (settings.clusterDomain) {
          const parts = settings.clusterDomain.split('.').reverse();
          await etcd.delete().key(`skydns/${parts.join('/')}/${node.name}`);
        }
      }
    }
  } catch (e) {
    console.warn(`[DB] Failed to clean up SkyDNS for node ${id}: ${e.message}`);
  }

  await db.delete(`${NODE_PREFIX}${id}`);
};

export const getLocalNodeConfig = async () => {
  const nodes = await getNodes();
  const interfaces = os.networkInterfaces();
  const localIps = [];
  for (const name of Object.keys(interfaces)) {
    for (const iface of interfaces[name]) {
      if (!iface.internal && iface.family === 'IPv4') {
        localIps.push(iface.address);
      }
    }
  }

  // Find node by IP (match either backhaul or client IP)
  let localNode = nodes.find(n => localIps.includes(n.ip) || (n.clientIp && localIps.includes(n.clientIp)));
  
  // If not found, check if we have system-wide defaults
  if (!localNode) {
    return {
      backupPath: process.env.HOST_BACKUP_PATH || '/data/backup',
      nonBackupPath: process.env.HOST_NONBACKUP_PATH || '/data/non-backup'
    };
  }
  
  return localNode;
};

export const getContainers = async () => {
  try {
    const allContainers = await db.getAll(PREFIX);
    return Object.values(allContainers).filter(v => v !== null && typeof v === 'object');
  } catch (e) {
    console.error(`Failed to get containers from ETCD: ${e.message}`);
    return [];
  }
};
export const getContainerByName = async (name) => {
  const containers = await getContainers();
  return containers.find(c => c.name === name) || null;
};

export const saveContainer = async (id, name, config, status, docker_id = null, current_node = null) => {
  const container = { id, name, config, status, docker_id, current_node };
  const key = `${PREFIX}${id}`;
  await db.put(key, container);
};

export const updateContainerDockerId = async (id, docker_id) => {
  const c = await db.get(`${PREFIX}${id}`);
  if (c) {
    c.docker_id = docker_id;
    await db.put(`${PREFIX}${id}`, c);
  }
};
export const deleteContainer = async (id) => {
  await db.delete(`${PREFIX}${id}`);
};

export const getGroups = async () => {
  const allGroups = await db.getAll(GROUPS_PREFIX);
  return Object.values(allGroups);
};

export const saveGroup = async (id, name, config) => {
  const group = { id, name, config };
  await db.put(`${GROUPS_PREFIX}${id}`, group);
};

export const deleteGroup = async (id) => {
  await db.delete(`${GROUPS_PREFIX}${id}`);
};

export { etcd };
